(function() {
  // ===== 定价表（单位：¥/百万 tokens） =====
  // 分为 offpeak（非高峰/旧价格）和 peak（高峰时段价格，UTC+8 09:00-12:00 及 14:00-18:00）
  var PRICING = { 'deepseek-v4-flash': { offpeak: { hit: 0.02, miss: 1, output: 2 }, peak: { hit: 0.04, miss: 2, output: 4 } }, 'deepseek-v4-pro': { offpeak: { hit: 0.025, miss: 3, output: 6 }, peak: { hit: 0.05, miss: 6, output: 12 } } };
  // ===== 全局状态对象 =====
  // 涵盖当前存档、UI 开关、图表库加载状态、API 密钥、余额、设置和消息计数
  var state = { currentSave: null, saves: {}, lastUsage: null, panelOpen: false, chartPanelOpen: false, chartLibLoaded: false, chartModel: 'deepseek-v4-flash', compareBefore: null, compareAfter: null, apiKey: '', balance: null, customBalance: null, settings: { autoBalance: false, balanceInterval: 10, debug: false, debugHit: 10000, debugMiss: 5000, debugOutput: 2000, debugModel: 'deepseek-v4-flash', useNewPricing: false, newPricingDate: new Date('2026-07-15T00:00:00+08:00').getTime() }, messageCount: 0 };
  // ===== 判断是否为高峰时段（UTC+8 时区） =====
  // 高峰时段：09:00-12:00（540-720 min）和 14:00-18:00（840-1080 min）
  function isPeakHour(timestamp) { var d = new Date(timestamp); var totalMinutes = (d.getUTCHours() * 60 + d.getUTCMinutes() + 8 * 60) % 1440; return (totalMinutes >= 540 && totalMinutes < 720) || (totalMinutes >= 840 && totalMinutes < 1080); }
  var isInitDone = false;
  function shortModel(m) { return m.replace(/^deepseek-/, 'DS-'); }
  var initTimestamp = 0;
  // ===== 面板 HTML 模板（含内联 CSS 样式） =====
  // 使用字符串拼接而非模板字符串，所有 " 需转义为 \"
  var PANEL_HTML = "<style>@media(max-width:480px){.ds-grid-3{grid-template-columns:repeat(1,1fr) !important}}.ds-diff-del{background:rgba(255,100,100,0.3);color:#ff8888;text-decoration:line-through;padding:0 2px;border-radius:2px}.ds-diff-ins{background:rgba(52,211,153,0.3);color:#34d399;font-weight:bold;padding:0 2px;border-radius:2px}.ds-diff-ctx{color:#6b7280;opacity:0.7}.ds-diff-block{margin:4px 0 8px;padding:10px;background:#0e1520;border:1px solid #374151;border-radius:8px;line-height:1.6;word-break:break-all;font-size:12px}.ds-diff-full{display:none;margin-top:8px;padding:10px;background:#060a10;border:1px solid #374151;border-radius:6px;white-space:pre-wrap;word-break:break-all;font-size:12px}.ds-diff-full.open{display:block}.ds-compare-overlay{position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.65);z-index:999999;display:none}.ds-compare-panel{position:fixed;z-index:999999;background:#0e1520;border:1px solid #374151;font-family:system-ui,-apple-system,sans-serif;color:#e5e7eb;box-shadow:0 20px 60px rgba(0,0,0,0.5);display:flex;flex-direction:column;overflow:hidden;transition:transform 0.3s ease,opacity 0.3s ease;bottom:0!important;left:50%!important;transform:translateX(-50%) translateY(100%)!important;opacity:0!important;pointer-events:none!important;width:min(820px,100%)!important;max-height:85vh!important;border-radius:12px 12px 0 0!important}.ds-compare-panel.ds-open{transform:translateX(-50%) translateY(0)!important;opacity:1!important;pointer-events:auto!important}.ds-compare-body{flex:1;overflow-y:auto;padding:16px}@media(max-width:480px){.ds-compare-panel{width:100vw!important;height:100vh!important;max-height:none!important;border-radius:0!important;left:0!important;top:0!important;transform:translateY(100%)!important;transition:transform 0.2s ease,opacity 0.2s ease!important}.ds-compare-panel.ds-open{transform:translateY(0)!important;opacity:1!important}}}to{opacity:1;transform:scale(1)}}.ds-compare-header{display:flex;justify-content:space-between;align-items:center;padding:16px 20px;border-bottom:1px solid #374151;font-size:14px;font-weight:600;color:#f3f4f6;background:#0a1018;border-radius:12px 12px 0 0;flex-shrink:0}.ds-compare-body{padding:16px 18px}.ds-compare-info{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:16px;padding:10px 14px;background:#060a10;border-radius:8px;font-size:11px;color:#9ca3af}.ds-compare-info .ds-info-old{color:#6366f1;font-weight:600}.ds-compare-info .ds-info-new{color:#a78bfa;font-weight:600}.ds-diff-msg{margin-bottom:14px;padding:12px;background:#0a1018;border-radius:8px;border-left:3px solid #6366f1}.ds-diff-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;font-size:12px}.ds-diff-header b{color:#a5b4fc}.ds-chart-slider-track{position:relative;height:28px;background:#1e293b;border-radius:4px;margin:8px 0;cursor:pointer;user-select:none;touch-action:none}.ds-chart-slider-thumb{position:absolute;top:2px;bottom:2px;background:rgba(99,102,241,0.35);border:1px solid rgba(99,102,241,0.6);border-radius:3px;cursor:grab;min-width:20px;touch-action:none}.ds-chart-slider-thumb:active{cursor:grabbing}.ds-slider-handle{position:absolute;top:50%;transform:translateY(-50%);width:22px;height:22px;background:#818cf8;border:2px solid #6366f1;border-radius:50%;cursor:ew-resize;z-index:2;opacity:0;transition:opacity 0.15s;touch-action:none}.ds-chart-slider-thumb:hover .ds-slider-handle,.ds-chart-slider-track:hover .ds-slider-handle{opacity:1}.ds-slider-handle-left{left:-11px}.ds-slider-handle-right{right:-11px}.ds-chart-slider-label{text-align:center;font-size:11px;color:#6b7280;margin-top:4px;font-family:system-ui,-apple-system,sans-serif}</style><div style=\"margin-bottom:16px\"><div style=\"display:flex;gap:6px;margin-bottom:8px\"><select id=\"ds-save-select\" style=\"flex:1;min-width:0;padding:10px 12px;border:1px solid #374151;border-radius:8px;font-size:14px;background:#0e1520;color:#e5e7eb;outline:none;font-weight:500;font-family:system-ui,-apple-system,sans-serif;overflow:hidden;text-overflow:ellipsis\"><option value=\"\">加载中...</option></select><button id=\"ds-btn-new-save\" style=\"padding:10px 12px;border:1px solid #065f46;border-radius:8px;background:#065f46;color:#6ee7b7;font-size:12px;font-weight:600;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">+ 新建</button></div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-delete-save\" style=\"flex:1;padding:6px 10px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">删除当前存档</button><button id=\"ds-btn-delete-all\" style=\"flex:1;padding:6px 10px;border:1px solid #7f1d1d;border-radius:6px;background:#991b1b;color:#fecaca;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">清空全部存档</button></div></div><div id=\"ds-balance-box\" style=\"padding:14px;background:#0c1a2e;border:1px solid #2563eb;border-radius:10px;margin-bottom:4px\"><div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:8px\"><div style=\"font-size:12px;color:#93c5fd;font-weight:500\">账户余额</div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-query-balance\" style=\"padding:4px 10px;border:1px solid #3b82f6;border-radius:6px;background:#2563eb;color:white;font-size:11px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">查询</button></div></div><div id=\"ds-balance\" style=\"font-size:26px;font-weight:700;color:#60a5fa;font-family:system-ui,-apple-system,sans-serif\">¥0.00 CNY</div><div id=\"ds-balance-remaining\" style=\"font-size:14px;color:#34d399;margin-top:4px;font-weight:500;font-family:system-ui,-apple-system,sans-serif\"></div><div id=\"ds-balance-status\" style=\"font-size:11px;color:#93c5fd;margin-top:4px;font-weight:500\"></div></div><div id=\"ds-settings-toggle\" style=\"display:flex;align-items:center;justify-content:center;padding:6px 0;margin-bottom:12px;cursor:pointer;border:1px solid #374151;border-radius:0 0 8px 8px;background:#0a1018;border-top:none\"><span style=\"font-size:11px;color:#6b7280;font-weight:500;margin-right:6px\">展开设置</span><span id=\"ds-settings-arrow\" style=\"font-size:10px;color:#6b7280;transition:transform 0.2s\">▼</span></div><div id=\"ds-settings-panel\" style=\"display:none;margin-bottom:12px;padding:12px;background:#0e1520;border:1px solid #374151;border-radius:8px;max-height:60vh;overflow-y:auto;-webkit-overflow-scrolling:touch\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px\">设置</div><div style=\"display:flex;flex-direction:column;gap:10px\"><div style=\"margin-bottom:2px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px\">API密钥</div><div style=\"display:flex;gap:6px\"><input id=\"ds-api-key\" type=\"password\" placeholder=\"输入DeepSeek API密钥\" style=\"flex:1;padding:8px 10px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><button id=\"ds-btn-save-key\" style=\"padding:8px 12px;border:1px solid #374151;border-radius:6px;background:#374151;color:#e5e7eb;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">保存</button></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">自动校准余额</span><label style=\"position:relative;display:inline-block;width:44px;height:24px;cursor:pointer\"><input type=\"checkbox\" id=\"ds-auto-balance\" style=\"opacity:0;width:0;height:0\"><span style=\"position:absolute;top:0;left:0;right:0;bottom:0;background:#374151;border-radius:12px;transition:0.3s;cursor:pointer\"><span id=\"ds-auto-balance-slider\" style=\"position:absolute;height:18px;width:18px;left:3px;bottom:3px;background:white;border-radius:50%;transition:0.3s\"></span></span></label></div><div id=\"ds-auto-balance-interval\" style=\"display:none;margin-top:8px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">校准间隔</span><div style=\"display:flex;align-items:center;gap:8px\"><input type=\"number\" id=\"ds-balance-interval\" min=\"1\" max=\"100\" value=\"10\" style=\"width:60px;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;text-align:center;font-family:system-ui,-apple-system,sans-serif;outline:none\"><span style=\"font-size:12px;color:#9ca3af\">条消息</span></div></div></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px\">自定义余额</div><div style=\"font-size:12px;color:#6b7280;margin-bottom:8px\">手动设置余额，设置后将覆盖API查询值</div><div style=\"display:flex;gap:6px\"><input id=\"ds-custom-balance\" type=\"number\" step=\"0.01\" placeholder=\"输入余额金额\" style=\"flex:1;padding:8px 10px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:13px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><button id=\"ds-btn-save-balance\" style=\"padding:8px 12px;border:1px solid #065f46;border-radius:6px;background:#065f46;color:#6ee7b7;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">保存</button><button id=\"ds-btn-clear-balance\" style=\"padding:8px 12px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">清除</button></div><div id=\"ds-custom-balance-status\" style=\"font-size:11px;color:#6b7280;margin-top:4px\"></div></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">新价格机制</span><label style=\"position:relative;display:inline-block;width:44px;height:24px;cursor:pointer\"><input type=\"checkbox\" id=\"ds-use-new-pricing\" style=\"opacity:0;width:0;height:0\"><span style=\"position:absolute;top:0;left:0;right:0;bottom:0;background:#374151;border-radius:12px;transition:0.3s;cursor:pointer\"><span id=\"ds-use-new-pricing-slider\" style=\"position:absolute;height:18px;width:18px;left:3px;bottom:3px;background:white;border-radius:50%;transition:0.3s\"></span></span></label></div><div id=\"ds-new-pricing-panel\" style=\"display:none;margin-top:8px\"><div style=\"display:flex;align-items:center;gap:6px;margin-bottom:6px\"><span style=\"font-size:11px;color:#6b7280;white-space:nowrap\">生效日期</span><input type=\"date\" id=\"ds-new-pricing-date\" style=\"flex:1;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><button id=\"ds-btn-pricing-today\" style=\"padding:4px 8px;border:1px solid #374151;border-radius:4px;background:#0e1520;color:#60a5fa;font-size:11px;cursor:pointer;font-family:system-ui,-apple-system,sans-serif;white-space:nowrap\">今天</button></div><div style=\"font-size:10px;color:#6b7280;line-height:1.5\"><div>高峰时段：每日 9:00~12:00, 14:00~18:00 （北京时间）</div><div style=\"margin-top:2px\">该时间之前的请求统一使用旧价格</div></div><div id=\"ds-new-pricing-status\" style=\"font-size:11px;color:#6b7280;margin-top:4px\"></div></div></div><div style=\"border-top:1px solid #374151;padding-top:10px\"><div style=\"display:flex;align-items:center;justify-content:space-between\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">调试模式</span><label style=\"position:relative;display:inline-block;width:44px;height:24px;cursor:pointer\"><input type=\"checkbox\" id=\"ds-debug-mode\" style=\"opacity:0;width:0;height:0\"><span style=\"position:absolute;top:0;left:0;right:0;bottom:0;background:#374151;border-radius:12px;transition:0.3s;cursor:pointer\"><span id=\"ds-debug-mode-slider\" style=\"position:absolute;height:18px;width:18px;left:3px;bottom:3px;background:white;border-radius:50%;transition:0.3s\"></span></span></label></div><div id=\"ds-debug-panel\" style=\"display:none;margin-top:8px\"><div style=\"font-size:11px;color:#6b7280;margin-bottom:8px\">\u6A21\u62DF\u5355\u6B21\u5BF9\u8BDD\u7684token\u6D88\u8017\u53C2\u6570\uFF0C\u4E0D\u4F1A\u4EA7\u751FAPI\u8D39\u7528</div><div style=\"display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:6px\"><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u7F13\u5B58\u547D\u4E2D tokens</div><input id=\"ds-debug-hit\" type=\"number\" min=\"0\" value=\"10000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u7F13\u5B58\u672A\u547D\u4E2D tokens</div><input id=\"ds-debug-miss\" type=\"number\" min=\"0\" value=\"5000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u8F93\u51FA tokens</div><input id=\"ds-debug-output\" type=\"number\" min=\"0\" value=\"2000\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"></div><div><div style=\"font-size:10px;color:#9ca3af;margin-bottom:2px\">\u6A21\u578B</div><select id=\"ds-debug-model\" style=\"width:100%;padding:6px 8px;border:1px solid #374151;border-radius:6px;background:#080d14;color:#e5e7eb;font-size:12px;font-family:system-ui,-apple-system,sans-serif;outline:none\"><option value=\"deepseek-v4-flash\">deepseek-v4-flash</option><option value=\"deepseek-v4-pro\">deepseek-v4-pro</option></select></div></div><div id=\"ds-debug-status\" style=\"font-size:11px;color:#34d399\"></div></div></div></div><details id=\"ds-help-section\" style=\"margin-bottom:12px;border:1px solid #374151;border-radius:8px;overflow:hidden\"><summary id=\"ds-help-header\" style=\"padding:10px 12px;background:#0e1520;cursor:pointer;display:flex;justify-content:space-between;align-items:center;list-style:none\"><div style=\"display:flex;align-items:center;gap:8px\"><span style=\"font-size:13px;color:#e5e7eb;font-weight:500\">使用说明</span><span style=\"font-size:10px;color:#6b7280\">release2.18</span></div><span id=\"ds-help-arrow\" style=\"font-size:12px;color:#6b7280;transition:transform 0.2s\">▼</span></summary><div id=\"ds-help-content\" style=\"padding:12px;background:#060a10;font-size:12px;color:#9ca3af;line-height:1.6;font-family:system-ui,-apple-system,sans-serif\"><div style=\"margin-bottom:12px\"><div style=\"font-size:11px;color:#f87171;font-weight:600;margin-bottom:4px\">⚠️ 安全提示</div><div>在本插件中填入API密钥存在安全风险。密钥存储在SillyTavern变量系统中，建议使用权限受限的API密钥。</div></div><div style=\"margin-bottom:10px\"><div style=\"font-size:11px;color:#60a5fa;font-weight:600;margin-bottom:4px\">📊 使用统计</div><div><div>1. 输入API密钥并保存后点击“查询”获取余额</div><div>2. 正常对话，插件自动记录每次请求的费用、token数及缓存命中</div><div>3. 切换存档或选择“全部存档”查看合并统计</div></div></div><div style=\"margin-bottom:10px\"><div style=\"font-size:11px;color:#34d399;font-weight:600;margin-bottom:4px\">🔄 消息对比</div><div><div>1. 在历史记录中找到想对比的两条消息</div><div>2. 前者点击「旧」，后者点击「新」</div><div>3. 弹出对比面板显示请求消息的文字差异</div><div>4. 差异点即缓存发散起始位置（前N条相同为缓存命中阶段）</div></div></div><div style=\"margin-bottom:10px\"><div style=\"font-size:11px;color:#fbbf24;font-weight:600;margin-bottom:4px\">📈 统计图表</div><div><div>1. 点击「统计图表」按钮打开图表页面</div><div>2. 切换模型查看对应数据（v4-flash / v4-pro）</div><div>3. 图表1/2：Token/费用趋势；图表3：缓存命中率</div><div>4. 可拖拽缩放、重置视图</div></div></div><div style=\"margin-bottom:10px\"><div style=\"font-size:11px;color:#a78bfa;font-weight:600;margin-bottom:4px\">💾 存档管理</div><div><div>1. 切换不同的存档文件管理多组统计数据</div><div>2. 删除单个存档或清空全部存档</div><div>3. 数据保存在SillyTavern localStorage中</div></div></div><div><div style=\"font-size:11px;color:#9ca3af;font-weight:600;margin-bottom:4px\">✨ 关于</div><div>本插件完全由AI编写，版本 release2.18</div></div></div></details><div style=\"display:flex;justify-content:space-between;align-items:center;margin-bottom:12px\"><div style=\"font-size:14px;font-weight:600;color:#e5e7eb;display:flex;align-items:center;gap:8px\"><div style=\"width:3px;height:14px;background:#818cf8;border-radius:2px\"></div><span>统计概览</span><span id=\"ds-btn-charts\" style=\"font-size:13px;cursor:pointer;color:#6b7280;margin-left:4px;margin-right:6px;transition:color 0.2s\" title=\"统计图\">📊 图表</span><span id=\"ds-save-time\" style=\"font-size:11px;color:#6b7280;font-weight:400\"></span></div><div style=\"display:flex;gap:6px\"><button id=\"ds-btn-refresh\" style=\"padding:6px 12px;border:1px solid #374151;border-radius:6px;background:#0e1520;color:#e5e7eb;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">刷新</button><button id=\"ds-btn-clear\" style=\"padding:6px 12px;border:1px solid #7f1d1d;border-radius:6px;background:#7f1d1d;color:#fca5a5;font-size:12px;font-weight:500;cursor:pointer;font-family:system-ui,-apple-system,sans-serif\">清空</button></div></div><div class=\"ds-grid-3\" style=\"display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:16px\"><div style=\"background:#0e1520;border:1px solid #374151;border-radius:8px;padding:14px\"><div style=\"font-size:11px;color:#9ca3af;font-weight:500;margin-bottom:6px;text-transform:uppercase;let