      return ['<div style="text-align:center;padding:40px;color:#6b7280"><div style="font-size:14px;color:#34d399;margin-bottom:8px">✔ 完全一致</div><div style="font-size:12px">两次请求的输入消息完全相同，缓存应当全部命中</div></div>'];
