          '<div style="color:#6b7280;font-size:11px;margin-bottom:2px">旧请求 <span style="color:#ff6464">0 字</span></div>' +
          '<div style="color:#666;font-style:italic;font-size:13px;padding:6px 0">∅</div>' +
